def topological_sort(n, edges):
    if n <= 0:
        return []
    from collections import deque
    adj = [[] for _ in range(n)]
    indeg = [0] * n
    for u, v in edges:
        if 0 <= u < n and 0 <= v < n:
            adj[u].append(v)
            indeg[v] += 1
    q = deque([i for i in range(n) if indeg[i] == 0])
    res = []
    while q:
        u = q.popleft()
        res.append(u)
        for v in adj[u]:
            indeg[v] -= 1
            if indeg[v] == 0:
                q.append(v)
    return res if len(res) == n else []
